      if (r.resolvedAt) html += `<div style="font-size:12px;color:var(--text-muted);margin-top:3px;">Resolved: ${new Date(r.resolvedAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</div>`;
      if (r.expiredAt) html += `<div style="font-size:12px;color:var(--text-muted);margin-top:3px;">Expired: ${new Date(r.expiredAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</div>`;
      if (r.withdrawnAt) html += `<div style="font-size:12px;color:var(--text-muted);margin-top:3px;">Withdrawn: ${new Date(r.withdrawnAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</div>`;
