  const qSubRevVals = JSON.stringify(data.quarters.map((q) => parseFloat(q.subRev.toFixed(2))));
  const qTaxVals = JSON.stringify(data.quarters.map((q) => parseFloat(((q.apptRev + q.subRev) * 0.3).toFixed(2))));
  const printDate = (/* @__PURE__ */ new Date()).toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" });
  const netIncome = data.thisYearTotal - data.thisYearExpenses;
